import {Audit, defaultConfig} from './core/index.js';
import {initializeConfig} from './core/config/config.js';

const flags = {onlyCategories: 'seo pwa best-practices accessibility'.split(' ')};
// const flags = {onlyCategories: ['performance']};
const {resolvedConfig} = await initializeConfig('navigation', defaultConfig, flags);
const nonManualAudits = resolvedConfig.audits.filter(a => {
  if (a.implementation.meta.scoreDisplayMode === Audit.SCORING_MODES.MANUAL) {
    return false;
  }
  return true;
});

const allArtifacts = new Set(nonManualAudits.map(a => a.implementation.meta.requiredArtifacts).flat());

const previous = [];
let prevArtifacts = new Set();
function filter(title, possibleUsedArtifacts) {
  let results = nonManualAudits.filter(a => {
    if (a.implementation.meta.scoreDisplayMode === Audit.SCORING_MODES.MANUAL) {
      return false;
    }
    for (const art of a.implementation.meta.requiredArtifacts) {
      if (!possibleUsedArtifacts.includes(art)) {
        return false;
      }
    }
    return true;
  }).map(a => a.implementation.meta.id).sort();

  const total = results.length;
  // Keep it additive.
  results = results.filter(id => !previous.includes(id));
  previous.push(...results);

  results = results
    .map(a => {
      const reqArtifacts = nonManualAudits
        .find(u => u.implementation.meta.id === a).implementation.meta.requiredArtifacts
        .map(a => prevArtifacts.has(a) ? strikeThrough(a) : a)
        .sort((a, b) => a.localeCompare(b));

      return {id: a.padEnd(35), reqArtifacts: reqArtifacts.toString()};
    })
    .sort((a, b) => a.reqArtifacts.localeCompare(b.reqArtifacts))
    .map(a => `${a.id} ${a.reqArtifacts}`);
  console.log(title, `(${total}/${nonManualAudits.length})`);
  console.log('- ' + results.join('\n- '));
  console.log();
  prevArtifacts = new Set([...Array.from(prevArtifacts), ...possibleUsedArtifacts]);
}

function strikeThrough(text) {
  return text
    .split('')
    .map(char => char + '\u0336')
    .join('');
}

console.log('(see source for tier classification of artifact intensity)');

const tier0 = [
  'GatherContext',
  'traces',
  'HostUserAgent',
  'settings',
  'URL',
];
const tier1 = [ // just CDP listening
  'ConsoleMessages',
  'InspectorIssues',
  'JsUsage',
  'devtoolsLogs',
];
const tier2 = [ // a basic eval plus getNodeDetails
  'ImageElements',
  'LinkElements',
  'MetaElements',
  'TraceElements',
  'Stacks', // one big eval

  // nonperf:
  'Doctype', // tiny eval
  'Accessibility',
  'Inputs', // big eval
  'AnchorElements',
  'EmbeddedContent', // aka EmbedElements
];
const tier3 = [ // a lil bit. evals or other CDP
  'CSSUsage', // listening + CSS.getStyleSheetText + eval
  'ResponseCompression', // Network.getResponseBody
  'Scripts', // listening + getscriptsource
  'SourceMaps', // network request for maps
  'ViewportDimensions',
  'DOMStats',
  'TagsBlockingFirstPaint', // like the *Elements gatherers, but with a Page.addScriptToEvaluateOnNewDocument

  // non-perf:
  'WebAppManifest', // Page.getAppManifest
  'InstallabilityErrors', // Page.getInstallabilityErrors
  'GlobalListeners', // evals + DOMDebugger.getEventListeners
  'MainDocumentContent', // responsebody
  'RobotsTxt', // 1 fetch
];
const tier4 = [ // lots of evals or other custom stuff
  'BFCacheFailures',
  'OptimizedImages', // uses Audits.getEncodedResponse to estimate jpeg/webp size. (checks all "optimizable" images until a 5sec budget)

  // non-perf
  'FontSize', // lotsss of cdp.
  'TapTargets', // lots of cdp
  ...Array.from(allArtifacts).filter(a => ![...tier0, ...tier1, ...tier2, ...tier3]),
];


filter('== audits using tier 0 artifacts (basics + trace)', tier0);
filter('== audits using above + tier 1 (CDP listening) artifacts', [...tier0, ...tier1]);
filter('== audits using above + tier2 (1 easy eval + getNodeDetails)', [...tier0, ...tier1, ...tier2]);
filter('== audits using above + tier3 (evals / other CDP)', [...tier0, ...tier1, ...tier2, ...tier3]);
filter('== audits using above + tier4 (lots of CDP)', [...tier0, ...tier1, ...tier2, ...tier3, ...tier4]);


console.log(Array.from(allArtifacts).filter(a => ![...tier0, ...tier1, ...tier2, ...tier3, ...tier4].includes(a)));
